import{_ as e,o as i,c as s,S as t}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"损失函数与梯度下降","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_12-loss_gradient.md","filePath":"直击概念/17ai/s_ai_12-loss_gradient.md","lastUpdated":1778207238000}'),n={name:"直击概念/17ai/s_ai_12-loss_gradient.md"};function l(r,a,o,h,d,p){return i(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="损失函数与梯度下降" tabindex="-1">损失函数与梯度下降 <a class="header-anchor" href="#损失函数与梯度下降" aria-label="Permalink to &quot;损失函数与梯度下降&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><h3 id="损失函数-loss-function" tabindex="-1">损失函数（Loss Function） <a class="header-anchor" href="#损失函数-loss-function" aria-label="Permalink to &quot;损失函数（Loss Function）&quot;">​</a></h3><p>损失函数用于<strong>量化模型预测结果与真实值之间的差距</strong>。L = f(预测值, 真实值)，值越小表示预测越准。</p><h3 id="梯度下降-gradient-descent" tabindex="-1">梯度下降（Gradient Descent） <a class="header-anchor" href="#梯度下降-gradient-descent" aria-label="Permalink to &quot;梯度下降（Gradient Descent）&quot;">​</a></h3><p>梯度下降是通过<strong>沿损失函数梯度反方向</strong>更新模型参数，逐步逼近最小值的优化算法。类比：你蒙着眼在山上要走到山谷（最低点），每次迈步都沿着脚下最陡的下降方向走。</p><h2 id="常见损失函数" tabindex="-1">常见损失函数 <a class="header-anchor" href="#常见损失函数" aria-label="Permalink to &quot;常见损失函数&quot;">​</a></h2><h3 id="分类问题" tabindex="-1">分类问题 <a class="header-anchor" href="#分类问题" aria-label="Permalink to &quot;分类问题&quot;">​</a></h3><p><strong>交叉熵损失（Cross-Entropy Loss）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>L = -Σ y_i · log(ŷ_i)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>y_i 为真实标签的 one-hot</li><li>ŷ_i 为模型预测的概率</li><li>LLM 每次预测下一个 token 使用的就是这个损失</li></ul><h3 id="回归问题" tabindex="-1">回归问题 <a class="header-anchor" href="#回归问题" aria-label="Permalink to &quot;回归问题&quot;">​</a></h3><p><strong>均方误差（MSE）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>L = (1/n) · Σ(y_i - ŷ_i)²</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>适合预测数值型结果，如房价预测。</p><p><strong>平均绝对误差（MAE）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>L = (1/n) · Σ|y_i - ŷ_i|</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>对异常值更稳健。</p><h2 id="梯度下降的变体" tabindex="-1">梯度下降的变体 <a class="header-anchor" href="#梯度下降的变体" aria-label="Permalink to &quot;梯度下降的变体&quot;">​</a></h2><h3 id="批量梯度下降-bgd" tabindex="-1">批量梯度下降（BGD） <a class="header-anchor" href="#批量梯度下降-bgd" aria-label="Permalink to &quot;批量梯度下降（BGD）&quot;">​</a></h3><p>每次用<strong>全部训练数据</strong>计算梯度：</p><ul><li>方向最准，但速度最慢，显存不够</li></ul><h3 id="随机梯度下降-sgd" tabindex="-1">随机梯度下降（SGD） <a class="header-anchor" href="#随机梯度下降-sgd" aria-label="Permalink to &quot;随机梯度下降（SGD）&quot;">​</a></h3><p>每次用<strong>一个样本</strong>计算梯度：</p><ul><li>速度快但方向不稳定，可能震荡</li></ul><h3 id="小批量梯度下降-mini-batch-sgd" tabindex="-1">小批量梯度下降（Mini-batch SGD） <a class="header-anchor" href="#小批量梯度下降-mini-batch-sgd" aria-label="Permalink to &quot;小批量梯度下降（Mini-batch SGD）&quot;">​</a></h3><p>每次用<strong>一小批样本</strong>（如 32/64 个）计算梯度：</p><ul><li>折中方案，LLM 训练中最常用</li><li>既高效又相对稳定</li></ul><h3 id="动量优化器" tabindex="-1">动量优化器 <a class="header-anchor" href="#动量优化器" aria-label="Permalink to &quot;动量优化器&quot;">​</a></h3><p><strong>Adam（Adaptive Moment Estimation）</strong></p><p>结合了 SGD + 动量 + 自适应学习率。当前最流行的优化器：</p><ul><li>自动调整每个参数的学习率</li><li>对稀疏梯度友好</li><li>AdamW 是变体，改进了权重衰减</li></ul><h2 id="学习率-learning-rate" tabindex="-1">学习率（Learning Rate） <a class="header-anchor" href="#学习率-learning-rate" aria-label="Permalink to &quot;学习率（Learning Rate）&quot;">​</a></h2><p>控制每次参数更新的步长：</p><ul><li><strong>太大</strong>：可能跳过最优解，甚至发散</li><li><strong>太小</strong>：收敛太慢</li><li><strong>学习率调度</strong>：训练中动态调整（warmup→平稳→衰减）</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>交叉熵损失为什么适合分类问题？</li><li>Adam 和 SGD 的核心区别是什么？</li><li>学习率太大或太小各有什么问题？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://ml-cheatsheet.readthedocs.io/en/latest/loss_functions.html" target="_blank" rel="noreferrer">Loss Functions - ML Glossary</a></li><li><a href="https://www.deeplearning.ai/" target="_blank" rel="noreferrer">Gradient Descent - DeepLearning.AI</a></li></ul>',39)])])}const g=e(n,[["render",l]]);export{u as __pageData,g as default};
